import React, { useState, useEffect } from 'react';

function PlayButton() {
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef(null);
  const streamUrl = 'http://172.232.62.146:8000/radio.mp3'; // Replace with your AzuraCast stream URL

  const handlePlayToggle = () => {
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  useEffect(() => {
    // Handle any additional logic here when the play state changes
  }, [isPlaying]);

  return (
    <button className="play-button" onClick={handlePlayToggle}>
      {isPlaying ? '❚❚' : '▶'}
      <audio ref={audioRef} src={streamUrl} />
    </button>
  );
}

export default PlayButton;
